class Solution:
    def gcdOfStrings(self, str1, str2):
        n1, n2 = len(str1), len(str2)
        for L in range(min(n1, n2), 0, -1):
            if n1 % L or n2 % L:
                continue
            cand = str1[:L]
            if cand * (n1 // L) == str1 and cand * (n2 // L) == str2:
                return cand
        return ''

